const items = $input.all();
const aq = items[0]?.json || {};
const reportData = items[1]?.json || {};

const aqi = aq.current?.european_aqi || 0;
const pm25 = aq.current?.pm2_5 || 0;
const pm10 = aq.current?.pm10 || 0;
const no2 = aq.current?.nitrogen_dioxide || 0;
const so2 = aq.current?.sulphur_dioxide || 0;
const o3 = aq.current?.ozone || 0;
const co = aq.current?.carbon_monoxide || 0;

const reports = reportData.reports || [];
const containmentReports = reports.filter(r => r.custom_fields?.containmentNeeded === true);
const airImpact = reports.filter(r => r.custom_fields?.airOrWaterImpact === 'air' || r.custom_fields?.airOrWaterImpact === 'mixed');

// EU AQI thresholds: 0-20 Good, 20-40 Fair, 40-60 Moderate, 60-80 Poor, 80-100 Very Poor, >100 Extremely Poor
let severity = 'Low';
let probability = 0.05;
let shouldAlert = false;
let primaryConcern = 'none';

if (aqi > 100 || so2 > 350 || co > 10000) {
  severity = 'Critical'; probability = 0.92; shouldAlert = true; primaryConcern = 'extreme_pollution';
} else if (aqi > 80 || pm25 > 25 || so2 > 200 || containmentReports.length >= 1) {
  severity = 'High'; probability = 0.70; shouldAlert = true; primaryConcern = 'poor_air_quality';
} else if (aqi > 60 || pm25 > 15 || no2 > 200 || reports.length >= 3) {
  severity = 'Medium'; probability = 0.40; shouldAlert = true; primaryConcern = 'moderate_pollution';
} else if (aqi > 40 || pm25 > 10) {
  severity = 'Low'; probability = 0.20; shouldAlert = false; primaryConcern = 'fair_air_quality';
}

return [{ json: {
  incidentType: 'environmental_hazard',
  severity,
  probability,
  aqi,
  pm25: Math.round(pm25 * 10) / 10,
  pm10: Math.round(pm10 * 10) / 10,
  no2: Math.round(no2 * 10) / 10,
  so2: Math.round(so2 * 10) / 10,
  o3: Math.round(o3 * 10) / 10,
  reportCount: reports.length,
  containmentRequired: containmentReports.length,
  primaryConcern,
  shouldAlert,
  timestamp: new Date().toISOString()
}}];
